script:
frappe.ui.form.on('Kafka Connector', {
    // Triggered when the 'doctype_used' field is changed
    doctype_used: function(frm) {
        console.log("changed");
        if (!frm.doc.doctype_used) {
            frm.clear_table('connector_fields');
            frm.refresh_field('connector_fields');
            return;
        }

        // Standard Frappe way to fetch DocType structure (meta)
        frappe.model.with_doctype(frm.doc.doctype_used, function() {
            let meta = frappe.get_meta(frm.doc.doctype_used);

            if (meta && meta.fields) {
                // 1. Clear existing rows to prevent duplicates on change
                frm.clear_table('connector_fields');

                // 2. Map through fields and exclude layout-only types
                meta.fields.forEach(f => {
                    const excludeTypes = ['Section Break', 'Column Break', 'Tab Break', 'HTML', 'Button'];

                    if (!excludeTypes.includes(f.fieldtype)) {
                        let row = frm.add_child('connector_fields');

                        // NOTE: Ensure 'field_name' matches the actual fieldname in your Child Table
                        row.field_name = f.fieldname; 
                        row.label = f.label;
                        row.field_type = f.fieldtype;
                        row.include = 0; 
                    }
                });

                // 3. UI Refresh
                frm.refresh_field('connector_fields');
                frappe.show_alert({
                    message: __('{0} fields loaded', [frm.doc.connector_fields.length]),
                    indicator: 'green'
                });
            }
        });
    },

    // Handles the initial load if the record already has a DocType selected
    onload: function(frm) {
        if (frm.is_new() && frm.doc.doctype_used) {
            frm.trigger('doctype_used');
        }
    },

    // Refresh logic to ensure the child table is visible and formatted
    refresh: function(frm) {
        // You can add custom buttons here later if needed
    }
});
